@Service
public class DeliveryService {
    public DeliveryResult processDelivery(DeliveryRequest req) {
        // 1. Validate route
        if (req.getStops().isEmpty()) throw new ValidationException("No stops");
        if (!routeExists(req.getRouteId())) throw new ValidationException("Invalid route");

        // 2. Calculate cost
        BigDecimal cost = req.getWeight().multiply(RATE);
        if (req.isExpress()) cost = cost.multiply(new BigDecimal("1.5"));
        if (req.getDistance() > 100) cost = cost.add(LONG_DISTANCE_FEE);

        // 3. Persist
        Delivery d = new Delivery(req, cost);
        deliveryRepository.save(d);

        // 4. Publish Kafka event
        kafkaTemplate.send("delivery-created", d.getId().toString(), toEvent(d));

        // 5. Notify driver
        pushService.send(req.getDriverId(), "New delivery: " + d.getId());

        // 6. Track analytics
        metricsService.increment("deliveries.created");
        analyticsClient.track("delivery", Map.of("type", req.getType().name()));

        return new DeliveryResult(d.getId(), cost);
    }
}

