@Service
public class LogisticsEventProcessor {
    private final Map<EventType, LogisticsEventHandler> handlers;

    public LogisticsEventProcessor(List<LogisticsEventHandler> handlers) {
        this.handlers = handlers.stream()
            .collect(Collectors.toMap(LogisticsEventHandler::supportedType, Function.identity()));
    }

    public void process(LogisticsEvent event) {
        LogisticsEventHandler handler = handlers.get(event.getType());
        if (handler == null) throw new UnsupportedOperationException("No handler for: " + event.getType());
        handler.handle(event);
    }
}

